INSERT INTO public.cv_infos (id, cv_file_id, full_name, email, phone, date_of_birth, address, summary, educations, created_at, updated_at, "position", total_experience_years, raw_text, profile_data, quality_details, quality_reason, quality_score, is_marked, tag, note, work_type) VALUES (75, 112, '', '', '', NULL, '', '', '[{"field": "", "degree": "", "university": "", "graduation_year": ""}]', '2026-06-24 18:28:04.476313', '2026-06-24 11:28:12.997983', '', 0, '', '{"data": {"job_position": "", "self_evaluation": "", "work_experience": [{"company": "", "duration": "", "position": "", "responsibility": ""}], "basic_information": {"name": "", "email": "", "phone": "", "status": "Completed", "address": "", "date_of_birth": ""}, "education_background": [{"field": "", "degree": "", "university": "", "graduation_year": ""}], "skills_and_specialties": {"skills": [], "certifications": []}, "total_experience_years": 0}, "cv_id": "6bbe4dc5-352e-4247-ab10-417e899b5bae", "status": "success", "message": "CV đã được trích xuất cấu trúc thành công và lưu kho dưới dạng Semantic Chunking.", "raw_text": ""}', '{"education": {"score": 2.0, "reason": "Ứng viên đã tốt nghiệp từ một trường đại học kỹ thuật hoặc công nghệ hàng đầu với GPA cao hoặc có bài viết khoa học xuất sắc."}, "self_evaluation": {"score": 1.0, "reason": "Self-evaluation rõ ràng nhưng chưa thể hiện được sự kết nối giữa các điểm mạnh và lộ trình phát triển nghề nghiệp cụ thể."}, "work_experience": {"score": 3.5, "reason": "Ứng viên chưa có kinh nghiệm làm việc trong ngành nhưng đang hoàn thành năm cuối tại một trường đại học kỹ thuật hàng đầu."}, "basic_information": {"score": 1.5, "reason": "Ứng viên đã cung cấp đầy đủ thông tin liên lạc cơ bản (Email, Phone)."}, "skills_specialties": {"score": 4.0, "reason": "Ứng viên không có chứng chỉ chuyên môn hoặc kỹ năng cụ thể liên quan đến AI và ML, nhưng đã cung cấp thông tin về kiến thức cơ bản trong các thư viện như Scikit-learn và Pandas."}}', 'Tài liệu hồ sơ của ứng viên chưa có đủ chứng chỉ chuyên môn hoặc kỹ năng cụ thể liên quan đến AI và ML, nhưng đã cung cấp thông tin về kiến thức cơ bản trong các thư viện như Scikit-learn và Pandas. Ngoài ra, ứng viên đang hoàn thành năm cuối tại một trường đại học kỹ thuật hàng đầu với GPA cao.', 12, false, 'new', NULL, NULL);
INSERT INTO public.cv_infos (id, cv_file_id, full_name, email, phone, date_of_birth, address, summary, educations, created_at, updated_at, "position", total_experience_years, raw_text, profile_data, quality_details, quality_reason, quality_score, is_marked, tag, note, work_type) VALUES (76, 113, 'DungCT', 'email@example.com', '+84 123 456 789', NULL, 'Ho Chi Minh City, Vietnam', 'A dedicated Software Engineering student with a strong foundation in backend development and fullstack integration. Experienced in C#, ASP.NET Core, and modern web frameworks including React.js and Next.js. I am seeking a Backend/Fullstack Developer position where I can contribute to scalable web applications, collaborate within an Agile environment, and further hone my software engineering skills.', '[{"field": "", "degree": "", "university": "", "graduation_year": ""}]', '2026-06-24 18:29:13.375508', '2026-06-24 11:29:23.237872', 'Backend/Fullstack Developer', 2, 'DungCT
Ho Chi Minh City, Vietnam | email@example.com | +84 123 456 789 | github.com/username
OBJECTIVE
A dedicated Software Engineering student with a strong foundation in backend development and fullstack integration. Experienced in C#, ASP.NET Core, and modern web frameworks including React.js and Next.js. I am seeking a Backend/Fullstack Developer position where I can contribute to scalable web applications, collaborate within an Agile environment, and further hone my software engineering skills.
• Project: Claim Request System
– Developed the back-end for a web application using ASP.NET Core Web API and PostgreSQL hosted on Supabase. Used Cloudinary for image hosting service.
– Implemented JWT authentication for web application.
– Used axios to connect API to web application on React.js. Collaborated within a Scrum-driven development environment.
PROJECTS
AgroTemp Agricultural Short-Term Recruitment Platform
Jan 2026 – Jun 2026 Ho Chi Minh City, Vietnam
Leader, Fullstack Developer
• Lead a team of 5 members to developed a REST API using ASP.NET Core Web API and PostgreSQL server for said web application for Farmers and mobile application for Workers.
• Designed farmer’s portal user interface via Figma mockup, integrated and implemented via Axios and Next.js.
• Applied Continuous Integration and Deployment using Heroku and Vercel for said application.
• Developed a Wallet system for storing and managing user balance, implemented payment system via PayOS for top-up and withdrawals.
Everwell Healthcare
Leader, Backend Developer May 2025 - Aug 2025 Ho Chi Minh City, Vietnam
• Developed a REST API using ASP.NET Core Web API and PostgreSQL database deployed on Supabase. Lead a team consisting of 4 members.
• Designed customer user interface for booking consultant meetings, create STI testing schedules via Figma mockup and implemented via React.js.
• Used Daily.co API services for online meetings with consultants. Implemented VNPay for payment systems with refunds and transaction histories.
TECHNICAL SKILLS
• Programming Languages: C#, SQL (Postgres, SQL Server), Java, JavaScript, TypeScript, HTML/CSS.
• Frameworks: ASP.NET, Next.js, React.js, Nest.js, NUnit, Entity Framework Core (LINQ).
• Developer Tools: Git, Azure, Heroku, Vercel, VS Code, Visual Studio, Postman, Rider.
• Language: English (IELTS 7.0), Vietnamese (Native), Japanese (JLPT N5).', '{"data": {"job_position": "Backend/Fullstack Developer", "self_evaluation": "A dedicated Software Engineering student with a strong foundation in backend development and fullstack integration. Experienced in C#, ASP.NET Core, and modern web frameworks including React.js and Next.js. I am seeking a Backend/Fullstack Developer position where I can contribute to scalable web applications, collaborate within an Agile environment, and further hone my software engineering skills.", "work_experience": [{"company": "AgroTemp Agricultural Short-Term Recruitment Platform", "duration": "Jan 2026 - Jun 2026", "position": "Leader, Fullstack Developer", "responsibility": "Lead a team of 5 members to developed a REST API using ASP.NET Core Web API and PostgreSQL server for said web application for Farmers and mobile application for Workers. Designed farmer’s portal user interface via Figma mockup, integrated and implemented via Axios and Next.js. Applied Continuous Integration and Deployment using Heroku and Vercel for said application. Developed a Wallet system for storing and managing user balance, implemented payment system via PayOS for top-up and withdrawals."}, {"company": "Everwell Healthcare", "duration": "May 2025 - Aug 2025", "position": "Backend Developer", "responsibility": "Developed a REST API using ASP.NET Core Web API and PostgreSQL database deployed on Supabase. Lead a team consisting of 4 members. Designed customer user interface for booking consultant meetings, create STI testing schedules via Figma mockup and implemented via React.js. Used Daily.co API services for online meetings with consultants. Implemented VNPay for payment systems with refunds and transaction histories."}], "basic_information": {"name": "DungCT", "email": "email@example.com", "phone": "+84 123 456 789", "status": "Completed", "address": "Ho Chi Minh City, Vietnam", "date_of_birth": ""}, "education_background": [{"field": "", "degree": "", "university": "", "graduation_year": ""}], "skills_and_specialties": {"skills": ["C#", "ASP.NET Core", "React.js", "Next.js", "Nest.js", "SQL (Postgres)", "Java", "JavaScript", "TypeScript", "HTML/CSS"], "certifications": ["IELTS 7.0"]}, "total_experience_years": 2}, "cv_id": "38c37905-2fdd-48dc-8a24-407407abd4c4", "status": "success", "message": "CV đã được trích xuất cấu trúc thành công và lưu kho dưới dạng Semantic Chunking.", "raw_text": "DungCT\nHo Chi Minh City, Vietnam | email@example.com | +84 123 456 789 | github.com/username\nOBJECTIVE\nA dedicated Software Engineering student with a strong foundation in backend development and fullstack integration. Experienced in C#, ASP.NET Core, and modern web frameworks including React.js and Next.js. I am seeking a Backend/Fullstack Developer position where I can contribute to scalable web applications, collaborate within an Agile environment, and further hone my software engineering skills.\n• Project: Claim Request System\n– Developed the back-end for a web application using ASP.NET Core Web API and PostgreSQL hosted on Supabase. Used Cloudinary for image hosting service.\n– Implemented JWT authentication for web application.\n– Used axios to connect API to web application on React.js. Collaborated within a Scrum-driven development environment.\nPROJECTS\nAgroTemp Agricultural Short-Term Recruitment Platform\nJan 2026 – Jun 2026 Ho Chi Minh City, Vietnam\nLeader, Fullstack Developer\n• Lead a team of 5 members to developed a REST API using ASP.NET Core Web API and PostgreSQL server for said web application for Farmers and mobile application for Workers.\n• Designed farmer’s portal user interface via Figma mockup, integrated and implemented via Axios and Next.js.\n• Applied Continuous Integration and Deployment using Heroku and Vercel for said application.\n• Developed a Wallet system for storing and managing user balance, implemented payment system via PayOS for top-up and withdrawals.\nEverwell Healthcare\nLeader, Backend Developer May 2025 - Aug 2025 Ho Chi Minh City, Vietnam\n• Developed a REST API using ASP.NET Core Web API and PostgreSQL database deployed on Supabase. Lead a team consisting of 4 members.\n• Designed customer user interface for booking consultant meetings, create STI testing schedules via Figma mockup and implemented via React.js.\n• Used Daily.co API services for online meetings with consultants. Implemented VNPay for payment systems with refunds and transaction histories.\nTECHNICAL SKILLS\n• Programming Languages: C#, SQL (Postgres, SQL Server), Java, JavaScript, TypeScript, HTML/CSS.\n• Frameworks: ASP.NET, Next.js, React.js, Nest.js, NUnit, Entity Framework Core (LINQ).\n• Developer Tools: Git, Azure, Heroku, Vercel, VS Code, Visual Studio, Postman, Rider.\n• Language: English (IELTS 7.0), Vietnamese (Native), Japanese (JLPT N5)."}', '{"education": {"score": 2.0, "reason": "Ứng viên không có thông tin về giáo dục hoặc chứng chỉ chuyên môn."}, "self_evaluation": {"score": 1.0, "reason": "Ứng viên mô tả mình là một lập trình viên phần mềm với nền tảng vững chắc trong phát triển backend và fullstack, tuy nhiên chưa cung cấp đủ thông tin về kỹ năng và kinh nghiệm làm việc cụ thể."}, "work_experience": {"score": 3.5, "reason": "Ứng viên đã có ít nhất 2 năm kinh nghiệm làm việc trong các vị trí như Lead Fullstack Developer và Backend Developer. Tuy nhiên, công ty mà ứng viên làm việc không được liệt kê rõ ràng, cũng như không có thông tin chi tiết về trách nhiệm cụ thể."}, "basic_information": {"score": 1.5, "reason": "Ứng viên có địa chỉ và thông tin liên lạc rõ ràng, nhưng không có thông tin về giáo dục hoặc kinh nghiệm làm việc cụ thể."}, "skills_specialties": {"score": 4.0, "reason": "Ứng viên đã cung cấp một danh sách kỹ năng và chứng chỉ chuyên môn đầy đủ, bao gồm các ngôn ngữ lập trình, framework và công nghệ liên quan đến phát triển backend và fullstack."}}', 'Tổng điểm của ứng viên là 12.0, tương ứng với mức độ 3.5 - 5.0 trong tài liệu tiêu chí. Tuy nhiên, ứng viên cần cung cấp thêm thông tin về giáo dục và kinh nghiệm làm việc cụ thể để đạt được mức tối đa.', 12, false, 'new', NULL, NULL);
