INSERT INTO public.cv_infos (id, cv_file_id, full_name, email, phone, date_of_birth, address, summary, educations, created_at, updated_at, "position", total_experience_years, raw_text, profile_data, quality_details, quality_reason, quality_score, is_marked, tag, note, work_type) VALUES (107, 154, 'Kevin Nguyen', 'kevin.nguyen.dev@example.com', '+84 987 654 321', '2004-10-15', 'Ho Chi Minh City, Vietnam', 'Goal-oriented Fresher Java Developer with a strong foundation in Spring Boot and Microservices. Dedicated to building scalable backend systems and mastering clean code principles (SOLID). Proven ability to optimize database performance and implement secure authentication flows.', '[{"field": "Information Technology", "degree": "Bachelor of Information Technology", "university": "Saigon University", "graduation_year": "2026"}]', '2026-06-24 23:06:28.1259', '2026-06-24 16:06:35.273803', 'Fresher Java Backend Developer', 0, 'Kevin Nguyen
Fresher Java Backend Developer
DOB: 15/10/2004 | Ho Chi Minh City, Vietnam
kevin.nguyen.dev@example.com | +84 987 654 321 linkedin.com/in/kevinnguyendev | github.com/kevinnguyendev
OBJECTIVE
Goal-oriented Fresher Java Developer with a strong foundation in Spring Boot and Microservices. Dedicated to building scalable backend systems and mastering clean code principles (SOLID). Proven ability to optimize database performance and implement secure authentication flows.
EDUCATION
Saigon University
2022 – 2026 (Expected)
