INSERT INTO public.cv_infos (id, cv_file_id, full_name, email, phone, date_of_birth, address, summary, educations, created_at, updated_at, "position", total_experience_years, raw_text, profile_data, quality_details, quality_reason, quality_score, is_marked, tag, note, work_type) VALUES (115, 162, 'Bao Long Pham', 'baolong.pham.ml@example.com', '+84 965 432 109', '2004-11-05', 'Ho Chi Minh City, Vietnam', '', '[{"field": "", "degree": "Bachelor of Information Technology, Minor in Data Science", "university": "University of Science VNUHCM (HCMUS)", "graduation_year": "Expected Oct 2027"}]', '2026-06-24 23:08:52.309775', '2026-06-24 16:08:59.200059', 'Machine Learning Intern', 0, 'Bao Long Pham
Machine Learning Intern
DOB: 05/11/2004 | Ho Chi Minh City, Vietnam
baolong.pham.ml@example.com | +84 965 432 109
linkedin.com/in/baolongphamml | github.com/baolongphamml
EDUCATION
University of Science VNUHCM (HCMUS)
Aug 2023 – Expected Oct 2027
Ho Chi Minh City, Vietnam
Bachelor of Information Technology, Minor in Data Science
• Coursework: Data Structures, Algorithms, Databases, Computer Systems, Machine Learning, Data Mining, Data Visualization, Probability & Statistics, Natural Language Processing.
• GPA:
8.67/10 (as of May 2026)
PROJECTS
KKBox Customer Churn Prediction & AI Action Center
May 2026
Python, SQL, LightGBM, Power BI, Gemini API
• Engineered an end-to-end data pipeline on PostgreSQL, processing 30M+ raw transaction rows into a structured master_dataset via SQL-based RFM (Recency, Frequency, Monetary) feature engineering, reducing data volume by 97% before model training.
• Trained and benchmarked three classification models (LightGBM, XGBoost, Random Forest) on 825K users to predict churn; LightGBM achieved the best performance with AUC-ROC of 0.9517 and 80% recall on the churned class.
• Identified 61,922 high-risk users (churn probability >80%) representing 38M NTD in revenue at risk, by applying the trained model and segmenting outputs into four risk tiers for prioritized intervention.
• Integrated Google Gemini 2.5 Flash API to auto-generate personalized push notifications for each high-risk user profile, demonstrating a Prescriptive Analytics workflow bridging ML outputs and Marketing actions.
• Delivered a 3-page interactive Power BI dashboard (Churn Overview, Risk Model Analysis, AI Action Center) with synchronized slicers and DAX measures, enabling non-technical stakeholders to drill down from KPIs to individual user-level interventions.
Real-Time Pose Estimation & AI Push-Up Counter
March 2026
PyTorch, MMPose, Streamlit
• Deployed the RTMPose framework (CSPNeXt backbone, SimCC head) for real-time human pose estimation, achieving 1.9x faster inference (14.5 FPS) compared to HRNet baselines on consumergrade hardware.
• Conducted zero-shot evaluation on the Leeds Sports Pose (LSP) dataset, engineering an intersection mapping algorithm to resolve semantic mismatches between 17-point and 14-point skeletal formats.
• Developed a "Smart AI Push-Up Counter" web application, integrating a custom state machine for precise repetition tracking based on dynamic elbow joint angles.
• Implemented an anti-cheat posture validation system utilizing geometric vector analysis to monitor body alignment and provide real-time exercise feedback.
AIoT Elderly Fall Detection System
Jan 2026
Python, YOLO, ReactJS, Socket.IO
• Developed the frontend architecture using ReactJS for a real-time monitoring dashboard, integrating Socket.IO for instant alert popups with low latency.
• Conducted comprehensive Exploratory Data Analysis (EDA) and evaluated YOLOv10n performance, analyzing the trade-offs between inference speed (3.4 ms) and detection recall.
• Collaborated in building an end-to-end pipeline that processes live camera feeds to detect abnormal postures, achieving an mAP@50 of 85.4% and a 93% recall rate.
TECHNICAL SKILLS
• Languages: Python, SQL (PostgreSQL, MongoDB), C/C++
• AI, ML & LLM: PyTorch, Scikit-learn, XGBoost, LightGBM, YOLO, RT-DETR, MMPose, Gemini API
• Data & BI: Pandas, NumPy, SQLAlchemy, ETL, Feature Engineering, Power BI, DAX, Scrapy
• Frameworks: FastAPI, Streamlit, Socket.IO
• Tools & Platforms: GitHub, Docker, Jupyter, VS Code, LATEX', '{"data": {"job_position": "Machine Learning Intern", "self_evaluation": "", "work_experience": [{"company": "", "duration": "Aug 2023 – Expected Oct 2027", "position": "Machine Learning Intern", "responsibility": ""}], "basic_information": {"name": "Bao Long Pham", "email": "baolong.pham.ml@example.com", "phone": "+84 965 432 109", "status": "Completed", "address": "Ho Chi Minh City, Vietnam", "date_of_birth": "2004-11-05"}, "education_background": [{"field": "", "degree": "Bachelor of Information Technology, Minor in Data Science", "university": "University of Science VNUHCM (HCMUS)", "graduation_year": "Expected Oct 2027"}], "skills_and_specialties": {"skills": ["Python", "SQL (PostgreSQL, MongoDB)", "C/C++", "PyTorch", "Scikit-learn", "XGBoost", "LightGBM", "YOLO", "RT-DETR", "MMPose", "Gemini API"], "certifications": []}, "total_experience_years": 0}, "cv_id": "09432468-d31d-4492-bcb2-b4a457e7932a", "status": "success", "message": "CV đã được trích xuất cấu trúc thành công và lưu kho dưới dạng Semantic Chunking.", "raw_text": "Bao Long Pham\nMachine Learning Intern\nDOB: 05/11/2004 | Ho Chi Minh City, Vietnam\nbaolong.pham.ml@example.com | +84 965 432 109\nlinkedin.com/in/baolongphamml | github.com/baolongphamml\nEDUCATION\nUniversity of Science VNUHCM (HCMUS)\nAug 2023 – Expected Oct 2027\nHo Chi Minh City, Vietnam\nBachelor of Information Technology, Minor in Data Science\n• Coursework: Data Structures, Algorithms, Databases, Computer Systems, Machine Learning, Data Mining, Data Visualization, Probability & Statistics, Natural Language Processing.\n• GPA:\n8.67/10 (as of May 2026)\nPROJECTS\nKKBox Customer Churn Prediction & AI Action Center\nMay 2026\nPython, SQL, LightGBM, Power BI, Gemini API\n• Engineered an end-to-end data pipeline on PostgreSQL, processing 30M+ raw transaction rows into a structured master_dataset via SQL-based RFM (Recency, Frequency, Monetary) feature engineering, reducing data volume by 97% before model training.\n• Trained and benchmarked three classification models (LightGBM, XGBoost, Random Forest) on 825K users to predict churn; LightGBM achieved the best performance with AUC-ROC of 0.9517 and 80% recall on the churned class.\n• Identified 61,922 high-risk users (churn probability >80%) representing 38M NTD in revenue at risk, by applying the trained model and segmenting outputs into four risk tiers for prioritized intervention.\n• Integrated Google Gemini 2.5 Flash API to auto-generate personalized push notifications for each high-risk user profile, demonstrating a Prescriptive Analytics workflow bridging ML outputs and Marketing actions.\n• Delivered a 3-page interactive Power BI dashboard (Churn Overview, Risk Model Analysis, AI Action Center) with synchronized slicers and DAX measures, enabling non-technical stakeholders to drill down from KPIs to individual user-level interventions.\nReal-Time Pose Estimation & AI Push-Up Counter\nMarch 2026\nPyTorch, MMPose, Streamlit\n• Deployed the RTMPose framework (CSPNeXt backbone, SimCC head) for real-time human pose estimation, achieving 1.9x faster inference (14.5 FPS) compared to HRNet baselines on consumergrade hardware.\n• Conducted zero-shot evaluation on the Leeds Sports Pose (LSP) dataset, engineering an intersection mapping algorithm to resolve semantic mismatches between 17-point and 14-point skeletal formats.\n• Developed a \"Smart AI Push-Up Counter\" web application, integrating a custom state machine for precise repetition tracking based on dynamic elbow joint angles.\n• Implemented an anti-cheat posture validation system utilizing geometric vector analysis to monitor body alignment and provide real-time exercise feedback.\nAIoT Elderly Fall Detection System\nJan 2026\nPython, YOLO, ReactJS, Socket.IO\n• Developed the frontend architecture using ReactJS for a real-time monitoring dashboard, integrating Socket.IO for instant alert popups with low latency.\n• Conducted comprehensive Exploratory Data Analysis (EDA) and evaluated YOLOv10n performance, analyzing the trade-offs between inference speed (3.4 ms) and detection recall.\n• Collaborated in building an end-to-end pipeline that processes live camera feeds to detect abnormal postures, achieving an mAP@50 of 85.4% and a 93% recall rate.\nTECHNICAL SKILLS\n• Languages: Python, SQL (PostgreSQL, MongoDB), C/C++\n• AI, ML & LLM: PyTorch, Scikit-learn, XGBoost, LightGBM, YOLO, RT-DETR, MMPose, Gemini API\n• Data & BI: Pandas, NumPy, SQLAlchemy, ETL, Feature Engineering, Power BI, DAX, Scrapy\n• Frameworks: FastAPI, Streamlit, Socket.IO\n• Tools & Platforms: GitHub, Docker, Jupyter, VS Code, LATEX"}', '{"education": {"score": 1.5, "reason": "Học sinh tốt nghiệp từ trường đại học kỹ thuật công nghệ thông tin thuộc top-tier (University of Science VNUHCM)"}, "self_evaluation": {"score": 0.0, "reason": "Không có đánh giá bản thân cụ thể hoặc liên quan đến sự phù hợp với văn hóa doanh nghiệp"}, "work_experience": {"score": 0.0, "reason": "Không có kinh nghiệm làm việc"}, "basic_information": {"score": 1.5, "reason": "Học sinh tốt nghiệp từ trường đại học kỹ thuật công nghệ thông tin thuộc top-tier"}, "skills_specialties": {"score": 2.5, "reason": "Familiar with basic ML libraries and core frameworks like PyTorch or TensorFlow"}}', 'Đánh giá tổng quan cho thấy ứng viên có nền tảng học vấn từ một trường đại học kỹ thuật công nghệ thông tin thuộc top-tier, nhưng không có kinh nghiệm làm việc hoặc đánh giá bản thân cụ thể phù hợp với văn hóa doanh nghiệp. Điểm số được chia sẻ dựa trên các tiêu chí về giáo dục và kỹ năng chuyên môn.', 8, false, 'new', NULL, NULL);
