2024 2025', '{"data": {"job_position": "Intern", "self_evaluation": "Với kiến thức tích lũy khi học tại trường, tôi mong muốn ứng tuyển vào vị trí Intern của Công ty để có thể học hỏi những kiến thức, kinh nghiệm lập trình để mang lại những giá trị hữu ích cho doanh nghiệp và phát triển bản thân. Đồng thời, mục tiêu phát triển trong vòng 2 năm tới của tôi sẽ trở thành một kỹ sư cầu nối Nhật Bản.", "work_experience": [{"company": "", "duration": "11/2025 - 01/2026", "position": "Lập Trình Viên Full Stack", "responsibility": "Thiết kế kiến trúc hệ thống, thực hiện CRUD cơ bản và triển khai công nghệ. Công nghệ sử dụng: PHP, Laravel, Tailwind, AWS EC2, Gemini API, Websocket."}, {"company": "", "duration": "05/2025 - 08/2025", "position": "Lập Trình Viên Full Stack", "responsibility": "Thiết kế cơ sở dữ liệu quan hệ, thiết kế UI/UX, đồng thời tham gia code fullstack và kiểm thử hệ thống. Công nghệ sử dụng: Spring boot, ReactJS, RAG."}], "basic_information": {"name": "Trần Tiến Đạt", "email": "dattt130623@gmail.com", "phone": "0384280136", "status": "Completed", "address": "Số 24, Ngõ 230, Mễ trì thượng, Hà Nội", "date_of_birth": "1999-06-13"}, "education_background": [{"field": "", "degree": "Kĩ thuật phần mềm", "university": "Đại học FPT Hà Nội", "graduation_year": "2025"}], "skills_and_specialties": {"skills": ["Java", "PHP", "TypeScript", "Html", "Css"], "certifications": []}, "total_experience_years": 0}, "cv_id": "dddbb7eb-d5aa-46c2-9d03-9b90af8dc726", "status": "success", "message": "CV đã được trích xuất cấu trúc thành công và lưu kho dưới dạng Semantic Chunking.", "raw_text": "Trần Tiến Đạt Lập trình viên\n 0384280136\n 13/06/2003\n✉ dattt130623@gmail.com\n Số 24, Ngõ 230, Mễ trì thượng, Hà Nội\nHọc vấn\nKĩ thuật phần mềm 2021 2025 Đại học FPT Hà Nội\n• GPA: 3.0\n• Ngôn ngữ Nhật: N4+\nKỹ năng\nNgôn ngữ lập trình: Java, PHP,\nTypeScript, Html, Css\nFrameworks: Spring boot, ReactJS, Laravel\nKỹ năng làm việc nhóm\nSở thích\nC ầ\nu lông n\nN ấ u ă\nMục tiêu nghề nghiệp\nVới kiến thức tích lũy khi học tại trường, tôi mong muốn ứng tuyển vào vị trí Intern của Công ty để có thể học hỏi những kiến thức, kinh nghiệm lập trình để mang lại những giá trị hữu ích cho doanh nghiệp và phát triển bản thân. Đồng thời, mục tiêu phát triển trong vòng 2 năm tới của tôi sẽ trở thành một kĩ sư cầu nối Nhật Bản.\nDanh hiệu và giải thưởng\n2024/07\nHoàn thành chương trình thực tập tại Nhật Bản (3 tháng)\n2024\nGiải Nhì Cuộc Thi Thuyết Trình Tiếng Nhật\n2025/11 2026/01\nHoàn thành chương trình thực tập PHP tại Nal Việt Nam\nDự án\nLập Trình Viên Full Stack | Cá nhân\nDigital Account Shop\n11/2025 1/2026\nMô tả : Đây là hệ thống Digital account shop, với các tính năng như đăng bán, quản lý sản phẩm tài khoản kĩ thuật số, hệ thống đóng vai trò như người trung gian giúp sự mua bán diễn ra 1 cách minh bạch.Hệ thống có Tích hợp AI duyệt sản phẩm và được deploy ở AWS EC2.\nTrách nhiệm : Tôi chịu trách nhiệm thiết kế kiến trúc hệ thống, thực hiện các thao tác CRUD cơ bản và triển khai công nghệ.\nCông nghệ sử dụng : PHP, Laravel, Tailwind, AWS EC2, Gemini API, Websocket.\nLập Trình Viên Full Stack\n5/2025 8/2025\nApplying AI to personalize Japanese learning for FPT students\nMô tả : Đây là hệ thống quản lý khóa học có tích hợp AI để hỗ trợ người học. Hệ thống đóng vai trò như 1 công cụ hỗ trợ người học với các chứng năng chính như tư vấn lộ trình học, chữa bài kiểm tra, hỏi đáp về tài liệu học và Q&A. Hệ thống được phát triển theo quy trình Iterative Process.\nTrách nhiệm : Tôi chịu trách nhiệm thiết kế cơ sở dữ liệu quan hệ, thiết kế UI/UX, đồng thời tôi tham gia code fullstack và kiểm thử hệ thống. Công nghệ sử dụng : Spring boot, ReactJS, RAG.\nHoạt động\nThành viên\nTHAM GIA CÂU LẠC BỘ FBC CỦA TRƯỜNG\nTham gia các giải đấu do CLB tổ chức\n2024 2025"}', '{"education": {"score": 2.0, "reason": "Ứng viên đã chỉ ra rằng họ đang theo học tại một trường đại học FPT Hà Nội chuyên ngành Kỹ thuật phần mềm, đạt mức tối đa cho tiêu chí này."}, "self_evaluation": {"score": 1.0, "reason": "Ứng viên đã đưa ra mục tiêu nghề nghiệp rõ ràng nhưng chưa có sự kết nối chặt chẽ với các kỹ năng và kinh nghiệm của mình."}, "work_experience": {"score": 3.5, "reason": "Hồ sơ ứng viên có hai năm kinh nghiệm làm việc trong lĩnh vực lập trình, bao gồm cả vị trí Full Stack Developer tại các công ty không rõ tên. Đây là một điểm số cao do mức độ chuyên nghiệp và kỹ năng đã được chứng minh."}, "basic_information": {"score": 1.5, "reason": "Hồ sơ ứng viên đã chỉ ra địa chỉ cụ thể và thông tin liên lạc chính xác."}, "skills_specialties": {"score": 4.0, "reason": "Ứng viên có một loạt các kỹ năng lập trình mạnh mẽ bao gồm Java, PHP, TypeScript, HTML và CSS, cùng với việc sử dụng công nghệ như Laravel, Spring Boot, ReactJS, Tailwind, AWS EC2, Gemini API và Websocket. Đây là một điểm số cao do sự đa dạng của các kỹ năng và công nghệ đã được chứng minh trong thực tế làm việc."}}', 'Tài liệu hồ sơ ứng viên cho thấy họ có nền tảng học vấn vững chắc, nhiều năm kinh nghiệm trong lĩnh vực lập trình và một loạt các kỹ năng mạnh mẽ. Tuy nhiên, cần có sự kết nối rõ ràng hơn giữa các kỹ năng của ứng viên với mục tiêu nghề nghiệp cụ thể.', 12, false, 'new', NULL, NULL);
INSERT INTO public.cv_infos (id, cv_file_id, full_name, email, phone, date_of_birth, address, summary, educations, created_at, updated_at, "position", total_experience_years, raw_text, profile_data, quality_details, quality_reason, quality_score, is_marked, tag, note, work_type) VALUES (14, 16, 'PHẠM NGỌC LAN THY', 'pnthangkth@gmail.com', '0372192004', NULL, 'Hà Nội, Vietnam', 'AI Engineer with hands-on experience building LLM, RAG, and multimodal retrieval systems for education and medical use cases. Built end-to-end AI products spanning ingestion, indexing, orchestration, and evidence-grounded generation across 7 content formats, with a focus on retrieval quality, hallucination reduction, and production-ready APIs. Strong execution across Python, FastAPI, PyTorch, knowledge graphs, and agentic workflows.', '[{"field": "", "degree": "Computer Science", "university": "Posts and Telecommunications Institute of Technology (PTIT)", "graduation_year": "2026"}]', '2026-06-17 16:31:02.170756', '2026-06-17 16:31:02.170756', 'AI Engineer', 3, 'PHẠM NGỌC LAN THY
AI Engineer | LLM, RAG & Agentic Systems
Hà Nội, Vietnam | 0372192004 | pnthangkth@gmail.com | github.com/thangkh02
SUMMARY
AI Engineer with hands-on experience building LLM, RAG, and multimodal retrieval systems for education and medical use cases. Built end-to-end AI products spanning ingestion, indexing, orchestration, and evidence-grounded generation across 7 content formats, with a focus on retrieval quality, hallucination reduction, and production-ready APIs. Strong execution across Python, FastAPI, PyTorch, knowledge graphs, and agentic workflows.
EDUCATION
Posts and Telecommunications Institute of Technology (PTIT)
Computer Science
2022 – 2026
GPA: 3.23 / 4.00
PROJECTS
EduMentor Multi-Agent RAG Learning Platform
github.com/thangkh02/EduMentor
11/2025 – 12/2025
• Built an end-to-end multi-agent RAG platform that answered course questions across 7 content formats (PDF, TXT, DOC, slides, PPTX, images, video) by designing a unified ingestion, indexing, and retrieval pipeline.
• Implemented multimodal video Q&A that generated evidence-grounded answers from retrieved clips and transcripts by combining ASR, VLM-based understanding, and chunk-level retrieval.
• Developed an orchestration agent that improved response grounding by routing user intents, selecting tools, and synthesizing cited answers from retrieved context and external data sources.
• Reduced redundant recomputation for repeated queries by deploying GPTCache and retrieval-level caching for semantically similar requests.
• Shipped the platform as a web-ready backend within a 2-month development cycle using FastAPI, LangChain, PyTorch, MongoDB, and ChromaDB.
ViMed Medical Document RAG with Knowledge Graph Verification
github.com/thangkh02/VIMED-GRAPHRAG
12/2025 – 02/2026
• Built a medical GraphRAG system that improved evidence traceability by extracting knowledge triples with provenance and confidence metadata from document chunks.
• Designed a recursive tree index that enabled retrieval at multiple abstraction levels by clustering and summarizing documents into hierarchical representations.
• Engineered a hybrid retrieval pipeline that strengthened multi-hop reasoning by combining vector search with graph traversal to localize relevant subgraphs.
• Reduced unsupported responses by implementing a self-correcting verification loop that checked generated answers against citations and expanded retrieval when evidence was insufficient.
• Improved graph-based relevance modeling by training a Graph Neural Network for subgraph reranking and link prediction over the constructed knowledge graph.
• Delivered the system as a deployable API within a 3-month build cycle using FastAPI, PyTorch, ChromaDB, and Docker.
TECHNICAL SKILLS
Languages:
Python, Java, C/C++
Backend & APIs:
FastAPI, Flask, Django
ML / LLM:
PyTorch, Transformers, scikit-learn, TensorFlow/Keras, LangChain, LangGraph
RAG / AI Systems:
Vector Search, Knowledge Graph RAG, Multimodal RAG, PEFT (LoRA, QLoRA), Quantization, Distillation
Tools & Deployment:
Docker, MongoDB, ChromaDB, ONNX, llama.cpp, whisper.cpp, TFLite
CERTIFICATIONS
Samsung PTIT Applications of Algorithms (2024)
Samsung PTIT DevOps Fundamentals (2025)
British Council EnglishScore, B2 CEFR (2025)', '{"data": {"job_position": "AI Engineer", "self_evaluation": "AI Engineer with hands-on experience building LLM, RAG, and multimodal retrieval systems for education and medical use cases. Built end-to-end AI products spanning ingestion, indexing, orchestration, and evidence-grounded generation across 7 content formats, with a focus on retrieval quality, hallucination reduction, and production-ready APIs. Strong execution across Python, FastAPI, PyTorch, knowledge graphs, and agentic workflows.", "work_experience": [{"company": "Posts and Telecommunications Institute of Technology (PTIT)", "duration": "2022 – 2026", "position": "Computer Science", "responsibility": "Built an end-to-end multi-agent RAG platform that answered course questions across 7 content formats, implemented multimodal video Q&A, developed an orchestration agent for improved response grounding, reduced redundant recomputation with GPTCache and retrieval-level caching, and delivered the platform as a web-ready backend using FastAPI, LangChain, PyTorch, MongoDB, and ChromaDB. Built a medical GraphRAG system that improved evidence traceability by extracting knowledge triples, designed a recursive tree index for retrieval at multiple abstraction levels, engineered a hybrid retrieval pipeline to strengthen multi-hop reasoning, reduced unsupported responses with self-correcting verification loop, trained a Graph Neural Network for subgraph reranking and link prediction over the constructed knowledge graph, and delivered the system as a deployable API using FastAPI, PyTorch, ChromaDB, and Docker."}], "basic_information": {"name": "PHẠM NGỌC LAN THY", "email": "pnthangkth@gmail.com", "phone": "0372192004", "status": "Completed", "address": "Hà Nội, Vietnam", "date_of_birth": ""}, "education_background": [{"field": "", "degree": "Computer Science", "university": "Posts and Telecommunications Institute of Technology (PTIT)", "graduation_year": "2026"}], "skills