INSERT INTO public.cv_infos (id, cv_file_id, full_name, email, phone, date_of_birth, address, summary, educations, created_at, updated_at, "position", total_experience_years, raw_text, profile_data, quality_details, quality_reason, quality_score, is_marked, tag, note, work_type) VALUES (102, 149, 'Tuan Minh Hoang', 'tuanminh.ba@example.com', '+84 987 654 321', '2003-05-15', 'Da Nang, Vietnam', 'A dedicated Industrial Management student (Business Administration) at HCMUT with a strong passion for data. Currently expanding expertise in IT and data systems to effectively bridge the gap between business requirements and technical solutions as a Business Analyst.', '[{"field": "", "degree": "Bachelor of Industrial Management, Major in Business Administration", "university": "HCM City University of Technology (HCMUT)", "graduation_year": "2026"}]', '2026-06-25 05:44:49.81201', '2026-06-24 15:47:06.953757', 'Business Analyst Intern', 0, 'Tuan Minh Hoang
Business Analyst Intern
DOB: 15/05/2003 | Da Nang, Vietnam
tuanminh.ba@example.com | +84 987 654 321 linkedin.com/in/tuanminh-ba | github.com/tuanminh-ba
SUMMARY
A dedicated Industrial Management student (Business Administration) at HCMUT with a strong passion for data. Currently expanding expertise in IT and data systems to effectively bridge the gap between business requirements and technical solutions as a Business Analyst.
TECHNICAL SKILLS
• System Analysis & Design: DW/DSS Architecture, Requirement Elicitation for AI-driven applications, BPMN, UML.
• AI Solution Strategy: Implementing Web AI & AI Apps to optimize business decision-making processes; Deep understanding of AI-driven Data Mining approaches.
• Modern Development Workflow: Proficient in Vibe Coding (Cursor, Copilot, Gemini) to bridge the communication gap between business needs and technical implementation (Prototyping).
• Local AI Implementation: Knowledge of local LLM ecosystems (Ollama, Llama) for secure, internal business data processing and Decision Support.
KEY PROJECTS
Formula 1 Race Strategy DW/DSS System
Role: Team Leader (Managed a team of 5)
Tech Stack: Cursor, GitHub Copilot (Vibe Coding Workflow), SQL Server, Python, Ollama (Llama 3), Power BI.
• Business Logic Transformation: Leveraged Vibe Coding (Gemini/Cursor) to interpret complex FIA racing regulations and transform them into actionable Business Rules for the Decision Support System.
• Requirements Elicitation: Defined and documented critical strategy scenarios, including pit-stop optimization and tire compound selection (Hard/Medium/Soft) based on track temperature and weather forecasts.
• Decision Support Strategy: Developed risk analysis workflows for extreme race conditions, enabling strategists to make data-driven decisions rather than relying on intuition.
• Rapid Prototyping: Significantly reduced the lifecycle from requirement gathering to functional prototype by utilizing an AI-native development workflow.
WORK EXPERIENCE
MB BANK | Individual Customer Dept Intern
Jun 2024 – Oct 2025
• Analyzed customer financial needs to recommend optimal banking products (Loans, Digital accounts, QR solutions).
• Managed documentation and procedures for mortgage and consumer loans, ensuring accuracy and regulatory compliance.
• Facilitated international remittance processes, enhancing customer service efficiency and transaction security.
POPEYES & BANH MI OI | Service Crew (Lobby & Cashier)
Jun 2023 – Jun 2024
• Managed inventory levels and stock rotation for food and supplies to ensure operational continuity.
• Performed order verification (cross-checking app and in-store orders) to maintain 100% data and delivery accuracy.
• Developed problem-solving and communication skills by handling customer requests in a high-paced retail environment.
VOLUNTEER ACTIVITIES
