INSERT INTO public.cv_infos (id, cv_file_id, full_name, email, phone, date_of_birth, address, summary, educations, created_at, updated_at, "position", total_experience_years, raw_text, profile_data, quality_details, quality_reason, quality_score, is_marked, tag, note, work_type) VALUES (63, 99, 'DungCT', 'email@example.com', '+84 123 456 789', NULL, 'Ho Chi Minh City, Vietnam', 'A dedicated Software Engineering student with a strong foundation in backend development and fullstack integration. Experienced in C#, ASP.NET Core, and modern web frameworks including React.js and Next.js. I am seeking a Backend/Fullstack Developer position where I can contribute to scalable web applications, collaborate within an Agile environment, and further hone my software engineering skills.', '[{"field": "", "degree": "", "university": "", "graduation_year": ""}]', '2026-06-23 18:17:49.016334', '2026-06-23 11:18:02.100151', 'Backend/Fullstack Developer', 2, 'DungCT
Ho Chi Minh City, Vietnam | email@example.com | +84 123 456 789 | github.com/username
OBJECTIVE
A dedicated Software Engineering student with a strong foundation in backend development and fullstack integration. Experienced in C#, ASP.NET Core, and modern web frameworks including React.js and Next.js. I am seeking a Backend/Fullstack Developer position where I can contribute to scalable web applications, collaborate within an Agile environment, and further hone my software engineering skills.
• Project: Claim Request System
– Developed the back-end for a web application using ASP.NET Core Web API and PostgreSQL hosted on Supabase. Used Cloudinary for image hosting service.
– Implemented JWT authentication for web application.
– Used axios to connect API to web application on React.js. Collaborated within a Scrum-driven development environment.
PROJECTS
AgroTemp Agricultural Short-Term Recruitment Platform
Jan 2026 – Jun 2026 Ho Chi Minh City, Vietnam
Leader, Fullstack Developer
• Lead a team of 5 members to developed a REST API using ASP.NET Core Web API and PostgreSQL server for said web application for Farmers and mobile application for Workers.
• Designed farmer’s portal user interface via Figma mockup, integrated and implemented via Axios and Next.js.
• Applied Continuous Integration and Deployment using Heroku and Vercel for said application.
• Developed a Wallet system for storing and managing user balance, implemented payment system via PayOS for top-up and withdrawals.
Everwell Healthcare
Leader, Backend Developer May 2025 - Aug 2025 Ho Chi Minh City, Vietnam
• Developed a REST API using ASP.NET Core Web API and PostgreSQL database deployed on Supabase. Lead a team consisting of 4 members.
• Designed customer user interface for booking consultant meetings, create STI testing schedules via Figma mockup and implemented via React.js.
• Used Daily.co API services for online meetings with consultants. Implemented VNPay for payment systems with refunds and transaction histories.
TECHNICAL SKILLS
• Programming Languages: C#, SQL (Postgres, SQL Server), Java, JavaScript, TypeScript, HTML/CSS.
• Frameworks: ASP.NET, Next.js, React.js, Nest.js, NUnit, Entity Framework Core (LINQ).
• Developer Tools: Git, Azure, Heroku, Vercel, VS Code, Visual Studio, Postman, Rider.
• Language: English (IELTS 7.0), Vietnamese (Native), Japanese (JLPT N5).', '{"data": {"job_position": "Backend/Fullstack Developer", "self_evaluation": "A dedicated Software Engineering student with a strong foundation in backend development and fullstack integration. Experienced in C#, ASP.NET Core, and modern web frameworks including React.js and Next.js. I am seeking a Backend/Fullstack Developer position where I can contribute to scalable web applications, collaborate within an Agile environment, and further hone my software engineering skills.", "work_experience": [{"company": "Everwell Healthcare", "duration": "May 2025 - Aug 2025", "position": "Backend Developer", "responsibility": "Developed a REST API using ASP.NET Core Web API and PostgreSQL database deployed on Supabase. Lead a team consisting of 4 members."}, {"company": "AgroTemp Agricultural Short-Term Recruitment Platform", "duration": "Jan 2026 – Jun 2026", "position": "Leader, Fullstack Developer", "responsibility": "Lead a team of 5 members to developed a REST API using ASP.NET Core Web API and PostgreSQL server for said web application for Farmers and mobile application for Workers. Designed farmer’s portal user interface via Figma mockup, integrated and implemented via Axios and Next.js."}], "basic_information": {"name": "DungCT", "email": "email@example.com", "phone": "+84 123 456 789", "status": "Completed", "address": "Ho Chi Minh City, Vietnam", "date_of_birth": ""}, "education_background": [{"field": "", "degree": "", "university": "", "graduation_year": ""}], "skills_and_specialties": {"skills": ["C#", "ASP.NET Core", "React.js", "Next.js", "Nest.js", "SQL (Postgres, SQL Server)", "Java", "JavaScript", "TypeScript", "HTML/CSS"], "certifications": ["IELTS 7.0"]}, "total_experience_years": 2}, "cv_id": "897eb0ca-8626-4785-96a0-34711485de57", "status": "success", "message": "CV đã được trích xuất cấu trúc thành công và lưu kho dưới dạng Semantic Chunking.", "raw_text": "DungCT\nHo Chi Minh City, Vietnam | email@example.com | +84 123 456 789 | github.com/username\nOBJECTIVE\nA dedicated Software Engineering student with a strong foundation in backend development and fullstack integration. Experienced in C#, ASP.NET Core, and modern web frameworks including React.js and Next.js. I am seeking a Backend/Fullstack Developer position where I can contribute to scalable web applications, collaborate within an Agile environment, and further hone my software engineering skills.\n• Project: Claim Request System\n– Developed the back-end for a web application using ASP.NET Core Web API and PostgreSQL hosted on Supabase. Used Cloudinary for image hosting service.\n– Implemented JWT authentication for web application.\n– Used axios to connect API to web application on React.js. Collaborated within a Scrum-driven development environment.\nPROJECTS\nAgroTemp Agricultural Short-Term Recruitment Platform\nJan 2026 – Jun 2026 Ho Chi Minh City, Vietnam\nLeader, Fullstack Developer\n• Lead a team of 5 members to developed a REST API using ASP.NET Core Web API and PostgreSQL server for said web application for Farmers and mobile application for Workers.\n• Designed farmer’s portal user interface via Figma mockup, integrated and implemented via Axios and Next.js.\n• Applied Continuous Integration and Deployment using Heroku and Vercel for said application.\n• Developed a Wallet system for storing and managing user balance, implemented payment system via PayOS for top-up and withdrawals.\nEverwell Healthcare\nLeader, Backend Developer May 2025 - Aug 2025 Ho Chi Minh City, Vietnam\n• Developed a REST API using ASP.NET Core Web API and PostgreSQL database deployed on Supabase. Lead a team consisting of 4 members.\n• Designed customer user interface for booking consultant meetings, create STI testing schedules via Figma mockup and implemented via React.js.\n• Used Daily.co API services for online meetings with consultants. Implemented VNPay for payment systems with refunds and transaction histories.\nTECHNICAL SKILLS\n• Programming Languages: C#, SQL (Postgres, SQL Server), Java, JavaScript, TypeScript, HTML/CSS.\n• Frameworks: ASP.NET, Next.js, React.js, Nest.js, NUnit, Entity Framework Core (LINQ).\n• Developer Tools: Git, Azure, Heroku, Vercel, VS Code, Visual Studio, Postman, Rider.\n• Language: English (IELTS 7.0), Vietnamese (Native), Japanese (JLPT N5)."}', '{"education": {"score": 2.0, "reason": "Ứng viên chưa cung cấp thông tin về giáo dục đại học hoặc chứng chỉ chuyên môn."}, "self_evaluation": {"score": 1.0, "reason": "Ứng viên mô tả mình là một lập trình viên phần mềm với nền tảng vững chắc trong phát triển backend và fullstack integration, nhưng không cung cấp đủ bằng chứng cụ thể về kinh nghiệm làm việc hoặc kỹ năng."}, "work_experience": {"score": 3.5, "reason": "Ứng viên có kinh nghiệm làm việc trong hai công ty khác nhau với thời gian làm việc là 18 tháng (2 năm). Trong đó, ứng viên đã dẫn dắt một nhóm gồm 4 thành viên và 5 thành viên trong một dự án phát triển API backend sử dụng ASP.NET Core Web API và cơ sở dữ liệu PostgreSQL. Đây là những bằng chứng cho thấy ứng viên có kinh nghiệm làm việc và khả năng lãnh đạo."}, "basic_information": {"score": 1.5, "reason": "Hồ sơ ứng viên đã chỉ ra rằng anh ấy đang làm việc tại Ho Chi Minh City, Việt Nam và chưa có thông tin về giáo dục đại học hoặc chứng chỉ chuyên môn."}, "skills_specialties": {"score": 4.0, "reason": "Ứng viên đã chỉ ra các kỹ năng lập trình như C#, ASP.NET Core, React.js, Next.js, Nest.js, SQL (Postgres, SQL Server), Java, JavaScript, TypeScript, HTML/CSS. Ngoài ra, ứng viên cũng có chứng chỉ IELTS 7.0. Đây là những bằng chứng cho thấy ứng viên đã nắm vững các kỹ năng cần thiết để làm việc trong vị trí Backend/Fullstack Developer."}}', 'Tổng điểm của hồ sơ ứng viên là 12.0, với mức điểm cao nhất được trao cho kinh nghiệm làm việc và kỹ năng lập trình. Tuy nhiên, ứng viên chưa cung cấp đủ thông tin về giáo dục đại học hoặc chứng chỉ chuyên môn, điều này có thể ảnh hưởng đến khả năng của họ trong một môi trường công ty chuyên nghiệp.', 12, false, 'new', NULL, NULL);
