INSERT INTO public.work_experience (id, cv_info_id, company, "position", duration, responsibility) OVERRIDING SYSTEM VALUE VALUES (3, 29, 'Posts and Telecommunications Institute of Technology (PTIT)', 'Computer Science', '2022 – 2026', 'Built an end-to-end multi-agent RAG platform that answered course questions across 7 content formats, implemented multimodal video Q&A, developed an orchestration agent for improved response grounding, reduced redundant recomputation with GPTCache and retrieval-level caching, and delivered the platform as a web-ready backend using FastAPI, LangChain, PyTorch, MongoDB, and ChromaDB. Built a medical GraphRAG system that improved evidence traceability by extracting knowledge triples from document chunks, designed a recursive tree index for retrieval at multiple abstraction levels, engineered a hybrid retrieval pipeline combining vector search with graph traversal to localize relevant subgraphs, reduced unsupported responses by implementing a self-correcting verification loop, and delivered the system as a deployable API using FastAPI, PyTorch, ChromaDB, and Docker.');
INSERT INTO public.work_experience (id, cv_info_id, company, "position", duration, responsibility) OVERRIDING SYSTEM VALUE VALUES (8, 33, '', 'Lập Trình Viên Full Stack', '11/2025 - 01/2026', 'Thiết kế kiến trúc hệ thống, thực hiện CRUD cơ bản và triển khai công nghệ. Công nghệ sử dụng: PHP, Laravel, Tailwind, AWS EC2, Gemini API, Websocket.');
